const crypto = require('crypto');

const incoming = $input.first().json;
const headers = incoming.headers || {};

// Raw body is required for HMAC — parsed JSON would produce a different hash
const rawBody = incoming.rawBody || JSON.stringify(incoming.body || {});

const secret = $env.PROCORE_WEBHOOK_SECRET;
if (!secret) {
  throw new Error('PROCORE_WEBHOOK_SECRET env var not set on this n8n instance');
}

const signature = headers['x-procore-hmac-sha256'];
if (!signature) {
  throw new Error('Missing X-Procore-Hmac-SHA256 header — request rejected');
}

const expected = crypto
  .createHmac('sha256', secret)
  .update(rawBody, 'utf8')
  .digest('hex');

// Timing-safe comparison prevents timing attacks
let sigValid = false;
try {
  const sigBuf = Buffer.from(signature.replace('sha256=', ''), 'hex');
  const expBuf = Buffer.from(expected, 'hex');
  sigValid = sigBuf.length === expBuf.length && crypto.timingSafeEqual(sigBuf, expBuf);
} catch (e) {
  throw new Error(`HMAC comparison failed: ${e.message}`);
}

if (!sigValid) {
  throw new Error('HMAC signature mismatch — request rejected');
}

const body = incoming.body || {};

return [{
  json: {
    event_type:   body.event_type   || null,
    resource_id:  body.resource_id  || null,
    project_id:   body.project_id   || null,
    company_id:   body.company_id   || null,
    timestamp:    body.timestamp    || null,
    api_version:  body.api_version  || 'v1.0',
    n8n_execution_id: $execution.id,
    n8n_workflow_id:  $workflow.id,
    received_at: new Date().toISOString()
  }
}];

const paData   = $input.first().json;
const prevData = $('Filter: Payment Apps Only').first().json;

// Procore PaymentApplication nests the contract as contract.id
// Fallback to top-level contract_id if structure differs
const contractId =
  paData?.contract?.id ??
  paData?.contract_id ??
  null;

if (!contractId) {
  throw new Error(
    `Could not extract contract_id from PaymentApplication ${ prevData.resource_id }. ` +
    `Procore response keys: ${ Object.keys(paData).join(', ') }`
  );
}

return [{
  json: {
    ...prevData,
    procore_payment_app_id: Number(prevData.resource_id),
    procore_contract_id:    Number(contractId),
    payment_app_status:     paData.status          || null,
    payment_app_number:     paData.number          || null,
    payment_app_amount:     paData.billing_amount ?? paData.amount ?? null
  }
}];

const lookup    = $input.first().json;
const extracted = $('Extract Contract ID').first().json;

const detail = [
  `event:${ extracted.event_type }`,
  `pay_app_id:${ extracted.procore_payment_app_id }`,
  `contract_id:${ extracted.procore_contract_id }`,
  `pay_app_status:${ extracted.payment_app_status }`,
  extracted.payment_app_amount != null ? `amount:${ extracted.payment_app_amount }` : null
].filter(Boolean).join(' | ');

return [{
  json: {
    // W5 payload
    site_order_id:        lookup.site_order_id,
    triggered_by:         'procore_webhook',
    triggered_by_detail:  detail,
    // pass-through for 200 OK response body
    _meta: {
      order_number:              lookup.order_number,
      subcontractor_id:          lookup.subcontractor_id,
      procore_payment_app_id:    extracted.procore_payment_app_id,
      procore_contract_id:       extracted.procore_contract_id,
      payment_app_status:        extracted.payment_app_status,
      received_at:               extracted.received_at,
      n8n_execution_id:          extracted.n8n_execution_id
    }
  }
}];
